class Solution:
    def readBinaryWatch(self, turnedOn):
        def popcount(x):
            c = 0
            while x:
                c += x & 1
                x >>= 1
            return c
        res = []
        for total in range(1024):
            h = total >> 6
            m = total & 63
            if h <= 11 and m <= 59 and popcount(total) == turnedOn:
                res.append('%d:%02d' % (h, m))
        return res

