var readBinaryWatch = function(turnedOn) {
    const bits = (x) => { let c = 0; while (x) { c += x & 1; x >>= 1; } return c; };
    const res = [];
    for (let h = 0; h < 12; h++) {
        for (let m = 0; m < 60; m++) {
            if (bits(h) + bits(m) === turnedOn) {
                res.push(h + ':' + String(m).padStart(2, '0'));
            }
        }
    }
    return res;
};
